const body = $json.body ?? $json

const message = String(body.message ?? '').trim()
if (!message) {
  return [
    {
      json: {
        error: 'EMPTY_MESSAGE',
        answer: 'Vui long nhap noi dung can tra cuu.',
        cards: [],
        actions: [],
        meta: { intent: 'invalid', confidence: 1, calledTools: [], sources: [] },
      },
    },
  ]
}

const staffId = body.staffId ?? 'anonymous'
const parsedFacilityId = Number(body.facilityId)
const facilityId = Number.isInteger(parsedFacilityId) ? parsedFacilityId : undefined
const sessionId = body.sessionId ?? `${staffId}-${Date.now()}`
const sessionFacilityKey = facilityId ?? 'all'
const sessionKey = `hotel-assistant:${sessionFacilityKey}:${staffId}:${sessionId}`

const today = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Ho_Chi_Minh',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date())

return [
  {
    json: {
      message,
      sessionId,
      sessionKey,
      staffId,
      facilityId,
      today,
      timezone: 'Asia/Ho_Chi_Minh',
      pageContext: body.pageContext ?? {},
      guardrails: {
        mode: 'read_only',
        allowedMethods: ['GET'],
        deniedMethods: ['POST', 'PUT', 'PATCH', 'DELETE'],
      },
    },
  },
]

